// @ts-ignore
import {GChart} from 'vue-google-charts'
import Doughnut_summary from "../components/Doughnut_summary.vue";
import {Watch} from "vue-property-decorator";


Vue.component("GChart", GChart);
Vue.component("Doughnut_summary", Doughnut_summary);

@Component
export default class Home extends Vue {

    apiKey = "AIzaSyDdRmGhfE2hBf_DODRLnOH2Ww68B94h7bE";
    windowSummary: number = 0;
    length = 2;
    n = 0;

    next() {
        this.windowSummary = this.windowSummary + 1 === this.length
            ? 0
            : this.windowSummary + 1
    };

    prev() {
        this.windowSummary = this.windowSummary - 1 < 0
            ? this.length - 1
            : this.windowSummary - 1
    };

    get isMobile() {
        return window.innerWidth < 600;
    }

    get imgNum() {
        let num = Math.floor(Math.random() * Math.floor(7));  // 0-6
        return "1-" + num + ".webp"
    }


    fixParallax(offset: number): void {
        let parallax = document.getElementById("parallax1") as HTMLElement;
        let parallaxChild = parallax.firstChild as HTMLElement;
        let image = parallaxChild.firstChild as HTMLImageElement;
        let changes = offset + "px;";
        image.setAttribute("style", "top: " + changes);
    }

    mounted(): void {
        let imgHeight = 1280;
        let height = 500;
        let percentScrolled = (window.innerHeight - window.pageYOffset) / (height + window.innerHeight);
        let parallaxDist = imgHeight - height;
        let offset = -1.1 * Math.round(parallaxDist * percentScrolled);
        console.log(offset);
        this.fixParallax(offset);
    }


    // Array will be automatically processed with visualization.arrayToDataTable function
    map1Data: object = [
        ['Country', 'Popularity'],
        ['Germany', 200],
        ['United States', 300],
        ['Brazil', 400],
        ['Canada', 500],
        ['France', 600],
        ['RU', 700]
    ];
    map1Options: object = {
        backgroundColor: {fill: 'transparent'},
        colorAxis: {colors: ['yellow', 'red']},
